{
  "version": "Notebook/1.0",
  "items": [
    {
      "type": 1,
      "content": {
        "json": "## Threat Intelligence\n\nThis workbook provides visibility into threat indicators ingested from the Microsoft Threat Intelligence feed (MDTI) and connected Threat Intelligence Platforms (TIP)."
      },
      "name": "header"
    },
    {
      "type": 9,
      "content": {
        "version": "KqlParameterItem/1.0",
        "parameters": [
          {
            "id": "a1b2c3d4-0005-0001-0001-000000000001",
            "version": "KqlParameterItem/1.0",
            "name": "TimeRange",
            "type": 4,
            "isRequired": true,
            "value": {
              "durationMs": 604800000
            },
            "typeSettings": {
              "selectableValues": [
                { "durationMs": 3600000 },
                { "durationMs": 86400000 },
                { "durationMs": 604800000 },
                { "durationMs": 2592000000 },
                { "durationMs": 7776000000 }
              ]
            }
          }
        ]
      },
      "name": "parameters"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| summarize Count=count() by IndicatorType=ThreatType\n| order by Count desc",
        "size": 1,
        "title": "Indicators by Threat Type",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "piechart"
      },
      "name": "indicatorsByType"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| summarize Count=count() by bin(TimeGenerated, 1d)\n| order by TimeGenerated asc",
        "size": 0,
        "title": "Indicators Ingested Over Time",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "timechart"
      },
      "name": "indicatorsOverTime"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| where isnotempty(NetworkIP) or isnotempty(NetworkSourceIP) or isnotempty(NetworkDestinationIP)\n| extend IP = coalesce(NetworkIP, NetworkSourceIP, NetworkDestinationIP)\n| summarize Count=count() by IP\n| top 20 by Count desc",
        "size": 0,
        "title": "Top 20 IP Indicators",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table"
      },
      "name": "topIPIndicators"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| where isnotempty(DomainName) or isnotempty(Url)\n| extend Indicator = coalesce(DomainName, Url)\n| summarize Count=count() by Indicator\n| top 20 by Count desc",
        "size": 0,
        "title": "Top 20 Domain/URL Indicators",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table"
      },
      "name": "topDomainIndicators"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| summarize Count=count() by SourceSystem\n| order by Count desc",
        "size": 1,
        "title": "Indicators by Source",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "piechart"
      },
      "name": "indicatorsBySource"
    },
    {
      "type": 3,
      "content": {
        "version": "KqlItem/1.0",
        "query": "ThreatIntelligenceIndicator\n| where TimeGenerated {TimeRange}\n| where ConfidenceScore > 0\n| summarize AvgConfidence=avg(ConfidenceScore), Count=count() by ThreatType\n| order by Count desc",
        "size": 0,
        "title": "Average Confidence by Threat Type",
        "queryType": 0,
        "resourceType": "microsoft.operationalinsights/workspaces",
        "visualization": "table"
      },
      "name": "confidenceByType"
    }
  ],
  "styleSettings": {}
}
